using System.Collections;
using UnityEngine;

/// <summary>
/// Tarefa #29 — componente adicionado automaticamente pelo
/// <see cref="VfxPoolManager"/> a cada instância de VFX pooled. Guarda o
/// prefab de origem e devolve a instância à pool ao fim da duração definida
/// por <see cref="BeginLifetime"/> (calculada pelo VfxPoolManager a partir do
/// ParticleSystem do prefab, ou de "defaultLifetime").
/// </summary>
[DisallowMultipleComponent]
public class PooledVfxInstance : MonoBehaviour
{
    /// <summary>Prefab original usado para repor esta instância na pool correcta.</summary>
    public GameObject SourcePrefab { get; set; }

    private Coroutine _returnRoutine;

    /// <summary>(Re)inicia o temporizador de retorno à pool. Chamado pelo VfxPoolManager sempre que esta instância é (re)activada.</summary>
    public void BeginLifetime(float duration)
    {
        if (_returnRoutine != null) StopCoroutine(_returnRoutine);
        _returnRoutine = StartCoroutine(ReturnAfter(duration));
    }

    private IEnumerator ReturnAfter(float duration)
    {
        yield return new WaitForSeconds(duration);
        _returnRoutine = null;
        VfxPoolManager.Instance?.ReturnToPool(SourcePrefab, gameObject);
    }

    private void OnDisable()
    {
        if (_returnRoutine != null)
        {
            StopCoroutine(_returnRoutine);
            _returnRoutine = null;
        }
    }
}
